INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('after', 'op', 21, 'OP', '在……之后；追随', 'later than something or behind it in order', 'Wash your hands after the work is done.', '工作完成之后洗手。', '[{"w":"across","def":"across: 相关的动作或关系词","vs":"与 after 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"across\" / \"after\" 的替换练习"},{"w":"against","def":"against: 可帮助扩展句型的基础词","vs":"与 after 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"against\" / \"after\" 的替换练习"},{"w":"among","def":"among: 同一组 Basic English 操作词","vs":"与 after 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"among\" / \"after\" 的替换练习"}]'),
  ('against', 'op', 22, 'OP', '反对；靠着；逆着', 'in opposition to or touching for support', 'The ladder is against the wall.', '梯子靠在墙上。', '[{"w":"after","def":"after: 相关的动作或关系词","vs":"与 against 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"after\" / \"against\" 的替换练习"},{"w":"among","def":"among: 可帮助扩展句型的基础词","vs":"与 against 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"among\" / \"against\" 的替换练习"},{"w":"at","def":"at: 同一组 Basic English 操作词","vs":"与 against 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"at\" / \"against\" 的替换练习"}]'),
  ('among', 'op', 23, 'OP', '在……之中；在一群里', 'in the middle of a group or set', 'The small house is among tall trees.', '这座小房子在高树之间。', '[{"w":"against","def":"against: 相关的动作或关系词","vs":"与 among 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"against\" / \"among\" 的替换练习"},{"w":"at","def":"at: 可帮助扩展句型的基础词","vs":"与 among 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"at\" / \"among\" 的替换练习"},{"w":"before","def":"before: 同一组 Basic English 操作词","vs":"与 among 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"before\" / \"among\" 的替换练习"}]'),
  ('at', 'op', 24, 'OP', '在；向；以某点为目标', 'show a place, time, direction, or point', 'Meet me at the station at noon.', '中午在车站见我。', '[{"w":"among","def":"among: 相关的动作或关系词","vs":"与 at 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"among\" / \"at\" 的替换练习"},{"w":"before","def":"before: 可帮助扩展句型的基础词","vs":"与 at 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"before\" / \"at\" 的替换练习"},{"w":"between","def":"between: 同一组 Basic English 操作词","vs":"与 at 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"between\" / \"at\" 的替换练习"}]'),
  ('before', 'op', 25, 'OP', '在……之前；在前面', 'earlier than or in front of something', 'Read the question before you give an answer.', '回答之前先读题。', '[{"w":"at","def":"at: 相关的动作或关系词","vs":"与 before 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"at\" / \"before\" 的替换练习"},{"w":"between","def":"between: 可帮助扩展句型的基础词","vs":"与 before 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"between\" / \"before\" 的替换练习"},{"w":"by","def":"by: 同一组 Basic English 操作词","vs":"与 before 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"by\" / \"before\" 的替换练习"}]');
